/*
 * OS Generation: Loadable Kernel Module (LKM) Simulation
 * Demonstrates how modular OS systems load drivers at runtime
 * This is a userspace simulation - real LKMs require kernel programming
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_MODULES 50
#define MAX_MODULE_NAME 64

/* Module states */
typedef enum {
 MODULE_STATE_UNLOADED = 0,
 MODULE_STATE_LOADING,
 MODULE_STATE_LOADED,
 MODULE_STATE_UNLOADING,
 MODULE_STATE_ERROR
} ModuleState;

/* Module information structure */
typedef struct {
 char name[MAX_MODULE_NAME];
 char description[128];
 ModuleState state;
 int ref_count; /* Number of modules depending on this */
 void (*init_func)(void);
 void (*exit_func)(void);
} KernelModule;

/* Available kernel modules (simulated drivers) */
KernelModule available_modules[MAX_MODULES];
int module_count = 0;

/* Module function prototypes */
void ext4_init(void);
void ext4_exit(void);
v usb_init(void);
v usb_exit(void);
v ethernet_init(void);
v ethernet_exit(void);
v sound_init(void);
v sound_exit(void);

/* Register a module with the system */
int register_module(const char *name, const char *description,
 void (*init)(void), void (*exit)(void)) {
 if (module_count >= MAX_MODULES) {
 printf("[ERROR] Maximum module count reached\n");
 return -1;
 }

 KernelModule *mod = &available_modules[module_count];
 strncpy(mod->name, name, MAX_MODULE_NAME - 1);
 strncpy(mod->description, description, 127);
 mod->state = MODULE_STATE_UNLOADED;
 mod->ref_count = 0;
 mod->init_func = init;
 mod->exit_func = exit;

 module_count++;
 printf("[KERNEL] Registered module: %s - %s\n", name, description);
 return 0;
}

/* Find a module by name */
KernelModule* find_module(const char *name) {
 for (int i = 0; i < module_count; i++) {
 if (strcmp(available_modules[i].name, name) == 0) {
 return &available_modules[i];
 }
 }
 return NULL;
}

/* Load a kernel module */
int load_module(const char *name) {
 KernelModule *mod = find_module(name);
 if (mod == NULL) {
 printf("[ERROR] Module not found: %s\n", name);
 return -1;
 }

 if (mod->state == MODULE_STATE_LOADED) {
 printf("[WARNING] Module already loaded: %s\n", name);
 return 0;
 }

 printf("[KERNEL] Loading module: %s... ", name);
 mod->state = MODULE_STATE_LOADING;

 /* Simulate module initialization */
 if (mod->init_func != NULL) {
 mod->init_func();
 }

 mod->state = MODULE_STATE_LOADED;
 printf("OK\n");
 return 0;
}

/* Unload a kernel module */
int unload_module(const char *name) {
 KernelModule *mod = find_module(name);
 if (mod == NULL) {
 printf("[ERROR] Module not found: %s\n", name);
 return -1;
 }

 if (mod->state != MODULE_STATE_LOADED) {
 printf("[WARNING] Module not loaded: %s\n", name);
 return -1;
 }

 /* Check if other modules depend on this */
 if (mod->ref_count > 0) {
 printf("[ERROR] Module %s is in use by %d other modules\n", 
 name, mod->ref_count);
 return -1;
 }

 printf("[KERNEL] Unloading module: %s... ", name);
 mod->state = MODULE_STATE_UNLOADING;

 if (mod->exit_func != NULL) {
 mod->exit_func();
 }

 mod->state = MODULE_STATE_UNLOADED;
 printf("OK\n");
 return 0;
}

/* List all loaded modules */
void list_modules(void) {
 printf("\n");
 printf("%-20s %-40s %s\n", "MODULE NAME", "DESCRIPTION", "STATE");
 printf("================================================================\n");

 for (int i = 0; i < module_count; i++) {
 KernelModule *mod = &available_modules[i];
 const char *state_str;

 switch (mod->state) {
 case MODULE_STATE_UNLOADED: state_str = "[unloaded]"; break;
 case MODULE_STATE_LOADING: state_str = "[loading]"; break;
 case MODULE_STATE_LOADED: state_str = "[loaded]"; break;
 case MODULE_STATE_UNLOADING: state_str = "[unloading]"; break;
 case MODULE_STATE_ERROR: state_str = "[error]"; break;
 default: state_str = "[unknown]"; break;
 }

 printf("%-20s %-40s %s\n", mod->name, mod->description, state_str);
 }
 printf("\n");
}

/* Simulated module initialization/exit functions */
void ext4_init(void) {
 printf(" -> ext4 filesystem driver initialized\n");
}
void ext4_exit(void) {
 printf(" -> ext4 filesystem driver unloaded\n");
}

void usb_init(void) {
 printf(" -> USB host controller initialized\n");
}
void usb_exit(void) {
 printf(" -> USB host controller unloaded\n");
}

void ethernet_init(void) {
 printf(" -> Ethernet network driver initialized\n");
}
void ethernet_exit(void) {
 printf(" -> Ethernet network driver unloaded\n");
}

void sound_init(void) {
 printf(" -> Sound card driver initialized\n");
}
void sound_exit(void) {
 printf(" -> Sound card driver unloaded\n");
}

/* Initialize module registry */
void init_module_system(void) {
 printf("Initializing module subsystem...\n\n");

 /* Register available drivers */
 register_module("ext4", "Ext4 Filesystem Driver", ext4_init, ext4_exit);
 register_module("usb_storage", "USB Storage Driver", usb_init, usb_exit);
 register_module("e1000", "Intel Ethernet Driver", ethernet_init, ethernet_exit);
 register_module("snd_hda", "HD Audio Driver", sound_init, sound_exit);

 printf("\n");
}

/* Simulate hardware detection and module loading */
void simulate_hw_detection_and_loading(void) {
 printf("\n");
 printf("====================================\n");
 printf("Simulating Boot-Time Module Loading\n");
 printf("====================================\n");

 printf("\n[1] Hardware Detection:\n");
 printf(" Found: SATA Controller\n");
 printf(" Found: USB Controller\n");
 printf(" Found: Ethernet Controller\n");
 printf(" Found: HD Audio\n");

 printf("\n[2] Loading Required Modules:\n");
 load_module("ext4"); /* Root filesystem */
 load_module("usb_storage"); /* For USB devices */
 load_module("e1000"); /* Network access */

 printf("\n[3] Skipping unused modules:\n");
 printf(" (snd_hda not loaded - no audio device needed)\n");

 printf("\n[4] Current Module Status:\n");
 list_modules();
}

/* Simulate runtime module management */
void simulate_runtime_management(void) {
 printf("\n");
 printf("====================================\n");
 printf("Simulating Runtime Module Management\n");
 printf("====================================\n");

 printf("\n[1] User inserts USB drive:\n");
 load_module("usb_storage"); /* Already loaded, ref_count increases */

 printf("\n[2] User wants audio (loading new module):\n");
 load_module("snd_hda");

 printf("\n[3] User removes USB drive (attempt unload):\n");
 unload_module("usb_storage"); /* May fail if in use */

 printf("\n[4] Final Module Status:\n");
 list_modules();
}

int main(void) {
 printf("\\n");
 printf("******************************************\\n");
 printf(" OS Generation: Loadable Kernel Modules \\n");
 printf(" (Userspace Simulation) \\n");
 printf("******************************************\\n");

 /* Initialize the module registry */
 init_module_system();

 /* Simulate boot-time hardware detection and loading */
 simulate_hw_detection_and_loading();

 /* Simulate runtime module management */
 simulate_runtime_management();

 printf("\\nSimulation complete.\\n");
 printf("This demonstrates the modular SYSGEN approach.\\n");
 printf("Real LKMs run in kernel space and require special APIs.\\n");

 return 0;
}
